const item = $input.first().json;

// --- Token guard ---
// access_token must hold a usable (non-encrypted) OAuth 2.0 Bearer token.
// If your pipeline stores tokens encrypted, add your decryption logic here
// before this node and surface the result as access_token.
if (!item.access_token) {
  throw new Error(
    `Missing access_token for post id=${item.id}. Ensure the channels table stores a usable token in the access_token column.`
  );
}

// --- Author URN ---
// LinkedIn distinguishes personal profiles (urn:li:person) from org pages (urn:li:organization).
// The channels table should carry an account_type of 'person' or 'organization'.
// Defaults to 'organization' — most scheduled publishing is done from org pages.
const accountType = (item.account_type || 'organization').toLowerCase().trim();
const urnType = accountType === 'person' ? 'person' : 'organization';
const authorUrn = `urn:li:${urnType}:${item.account_id}`;

// --- Media ---
let mediaUrls = [];
if (item.media_urls) {
  try {
    mediaUrls = typeof item.media_urls === 'string'
      ? JSON.parse(item.media_urls)
      : item.media_urls;
  } catch (e) {
    mediaUrls = [];
  }
}

const hasMedia = Array.isArray(mediaUrls) && mediaUrls.length > 0;

// --- Build LinkedIn Posts API body ---
// Uses the current /rest/posts endpoint (UGC Posts was deprecated in 2023).
const postBody = {
  author: authorUrn,
  lifecycleState: 'PUBLISHED',
  visibility: 'PUBLIC',
  distribution: {
    feedDistribution: 'MAIN_FEED',
    targetEntities: [],
    thirdPartyDistributionChannels: []
  },
  commentary: item.content_text,
  content: hasMedia
    ? {
        media: {
          id: mediaUrls[0],
          title: ''
        }
      }
    : undefined
};

// Strip undefined keys so the API body stays clean
if (!postBody.content) delete postBody.content;

return {
  json: {
    post_id: item.id,
    access_token: item.access_token,
    post_body: postBody,
    has_media: hasMedia
  }
};

const response = $input.first().json;

// LinkedIn Posts API returns 201 Created on success.
// The post URN is in the x-restli-id response header (e.g. urn:li:share:123).
// The body is empty on success; errors come back as a JSON body with a 'message' field.
const statusCode = response.statusCode;
const headers = response.headers || {};
const body = response.body || {};

if (statusCode !== 201) {
  const errMsg = body.message || body.error || JSON.stringify(body);
  throw new Error(
    `LinkedIn API error [HTTP ${statusCode}]: ${errMsg}`
  );
}

// Extract the post URN from the response header
const externalPostId = headers['x-restli-id'] || headers['x-linkedin-id'] || body.id || null;

if (!externalPostId) {
  throw new Error(
    'LinkedIn API returned 201 but no post URN found in x-restli-id header or body.'
  );
}

return {
  json: {
    external_post_id: externalPostId,
    post_id: $('Transform - Prepare Post Payload').first().json.post_id
  }
};

